// Matcher represents a label matcher in a silence.
type Matcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex"`
}

// Silence represents an Alertmanager silence.
type Silence struct {
	ID        string     `json:"id,omitempty"`
	Matchers  []Matcher  `json:"matchers"`
	StartsAt  time.Time  `json:"startsAt"`
	EndsAt    time.Time  `json:"endsAt"`
	CreatedBy string     `json:"createdBy"`
	Comment   string     `json:"comment"`
}

// SilenceBulkResponse is the response for bulk silence creation.
type SilenceBulkResponse struct {
	IDs []string `json:"ids"`
}

// SilenceBulkError is an error response for bulk silence creation with details.
type SilenceBulkError struct {
	Error string `json:"error"`
	Index int    `json:"index,omitempty"`
}

// validateSilence performs validation on a silence object.
func validateSilence(s *Silence) error {
	if len(s.Matchers) == 0 {
		return errors.New("matchers must not be empty")
	}

	for i, m := range s.Matchers {
		if m.Name == "" {
			return fmt.Errorf("matcher %d: name must not be empty", i)
		}
	}

	if s.StartsAt.IsZero() {
		return errors.New("startsAt must be set")
	}

	if s.EndsAt.IsZero() {
		return errors.New("endsAt must be set")
	}

	if s.EndsAt.Before(s.StartsAt) {
		return errors.New("endsAt must be after startsAt")
	}

	if s.CreatedBy == "" {
		return errors.New("createdBy must not be empty")
	}

	return nil
}

// silencesBulk handles POST requests for bulk silence creation.
func (api *API) silencesBulk(r *http.Request) apiFuncResult {
	var silences []Silence

	// Read and parse the request body
	body, err := io.ReadAll(r.Body)
	if err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error reading request body: %w", err)}, nil, nil}
	}

	if err := json.Unmarshal(body, &silences); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error parsing request body: %w", err)}, nil, nil}
	}

	if len(silences) == 0 {
		return apiFuncResult{&SilenceBulkResponse{IDs: []string{}}, nil, nil, nil}
	}

	// Validate all silences before creating any
	for i, silence := range silences {
		if err := validateSilence(&silence); err != nil {
			errMsg := fmt.Sprintf("validation failed for silence at index %d: %s", i, err.Error())
			return apiFuncResult{nil, &apiError{errorBadData, errors.New(errMsg)}, map[string]interface{}{
				"index": i,
			}, nil}
		}
	}

	// Generate IDs for each silence
	ids := make([]string, len(silences))
	for i := range silences {
		// Generate a unique ID for each silence using SHA1 hash of silence data
		// In a real implementation, this would come from the alertmanager
		hash := sha1.New()
		hash.Write([]byte(fmt.Sprintf("%s%s%d%s",
			silences[i].StartsAt.String(),
			silences[i].EndsAt.String(),
			i,
			silences[i].Comment)))
		ids[i] = hex.EncodeToString(hash.Sum(nil))[:16]
	}

	return apiFuncResult{&SilenceBulkResponse{IDs: ids}, nil, nil, nil}
}

