    13→
    14→package v1
    15→
    16→import (
    17→	"crypto/sha1"
    18→	"encoding/hex"
    19→	"encoding/json"
    20→	"errors"
    21→	"fmt"
    22→	"io"
    23→	"net/http"
    24→	"time"
    25→)
    26→
    27→// Matcher represents a label matcher in a silence.
    28→type Matcher struct {
    29→	Name    string `json:"name"`
    30→	Value   string `json:"value"`
    31→	IsRegex bool   `json:"isRegex"`
    32→}
    33→
    34→// Silence represents an Alertmanager silence.
    35→type Silence struct {
    36→	ID        string     `json:"id,omitempty"`
    37→	Matchers  []Matcher  `json:"matchers"`
    38→	StartsAt  time.Time  `json:"startsAt"`
    39→	EndsAt    time.Time  `json:"endsAt"`
    40→	CreatedBy string     `json:"createdBy"`
    41→	Comment   string     `json:"comment"`
    42→}
    43→
    44→// SilenceBulkResponse is the response for bulk silence creation.
    45→type SilenceBulkResponse struct {
    46→	IDs []string `json:"ids"`
    47→}
    48→
    49→// SilenceBulkError is an error response for bulk silence creation with details.
    50→type SilenceBulkError struct {
    51→	Error string `json:"error"`
    52→	Index int    `json:"index,omitempty"`
    53→}
    54→
    55→// validateSilence performs validation on a silence object.
    56→func validateSilence(s *Silence) error {
    57→	if len(s.Matchers) == 0 {
    58→		return errors.New("matchers must not be empty")
    59→	}
    60→
    61→	for i, m := range s.Matchers {
    62→		if m.Name == "" {
    63→			return fmt.Errorf("matcher %d: name must not be empty", i)
    64→		}
    65→	}
    66→
    67→	if s.StartsAt.IsZero() {
    68→		return errors.New("startsAt must be set")
    69→	}
    70→
    71→	if s.EndsAt.IsZero() {
    72→		return errors.New("endsAt must be set")
    73→	}
    74→
    75→	if s.EndsAt.Before(s.StartsAt) {
    76→		return errors.New("endsAt must be after startsAt")
    77→	}
    78→
    79→	if s.CreatedBy == "" {
    80→		return errors.New("createdBy must not be empty")
    81→	}
    82→
    83→	return nil
    84→}
    85→
    86→// silencesBulk handles POST requests for bulk silence creation.
    87→func (api *API) silencesBulk(r *http.Request) apiFuncResult {
    88→	var silences []Silence
    89→
    90→	// Read and parse the request body
    91→	body, err := io.ReadAll(r.Body)
    92→	if err != nil {
    93→		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error reading request body: %w", err)}, nil, nil}
    94→	}
    95→
    96→	if err := json.Unmarshal(body, &silences); err != nil {
    97→		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error parsing request body: %w", err)}, nil, nil}
    98→	}
    99→
   100→	if len(silences) == 0 {
   101→		return apiFuncResult{&SilenceBulkResponse{IDs: []string{}}, nil, nil, nil}
   102→	}
   103→
   104→	// Validate all silences before creating any
   105→	for i, silence := range silences {
   106→		if err := validateSilence(&silence); err != nil {
   107→			errMsg := fmt.Sprintf("validation failed for silence at index %d: %s", i, err.Error())
   108→			return apiFuncResult{nil, &apiError{errorBadData, errors.New(errMsg)}, map[string]interface{}{
   109→				"index": i,
   110→			}, nil}
   111→		}
   112→	}
   113→
   114→	// Generate IDs for each silence
   115→	ids := make([]string, len(silences))
   116→	for i := range silences {
   117→		// Generate a unique ID for each silence using SHA1 hash of silence data
   118→		// In a real implementation, this would come from the alertmanager
   119→		hash := sha1.New()
   120→		hash.Write([]byte(fmt.Sprintf("%s%s%d%s",
   121→			silences[i].StartsAt.String(),
   122→			silences[i].EndsAt.String(),
   123→			i,
   124→			silences[i].Comment)))
   125→		ids[i] = hex.EncodeToString(hash.Sum(nil))[:16]
   126→	}
   127→
   128→	return apiFuncResult{&SilenceBulkResponse{IDs: ids}, nil, nil, nil}
   129→}
